const body = $input.first().json.body;
const email = (body.email || '').toLowerCase().trim();
const password = body.password || '';

// Usuarios autorizados del módulo de multiplicadores
// Formato: email → {password, role, nombre}
// Roles:
// admin    → acceso a multiplicadores + dashboard
// operator → acceso a multiplicadores + dashboard
// viewer   → acceso solo a dashboard
const USERS = {
  'jaime.chaves@nodo.live':          {password: 'CrackAdmin2026!', role: 'admin',    nombre: 'Jaime Chaves'},
  'daniela.corredor@nodo.live':      {password: 'CrackOp2026!',   role: 'operator', nombre: 'Daniela Corredor'},
  'laura.uribe@dipaolalatina.com':   {password: 'CrackOp2026!',   role: 'operator', nombre: 'Laura Uribe'},
  'camila.pulido@dipaolalatina.com': {password: 'CrackOp2026!',   role: 'operator', nombre: 'Camila Pulido'},
  'mariad.acosta@terpel.com':        {password: 'CrackView2026!', role: 'viewer',   nombre: 'Maria D. Acosta'},
  'ingrith.cuellar@terpel.com':      {password: 'CrackView2026!', role: 'viewer',   nombre: 'Ingrith Cuellar'},
  'lorenza.arroyave@terpel.com':     {password: 'CrackView2026!', role: 'viewer',   nombre: 'Lorenza Arroyave'}
};

if (!email || !password) {
  return [{json: {ok: false, error: 'Email y contraseña requeridos'}}];
}

const user = USERS[email];
if (!user || user.password !== password) {
  return [{json: {ok: false, error: 'Credenciales incorrectas'}}];
}

// Token simple: base64 del email + timestamp + secret
const secret = 'CrackTesos2026_Admin_Token';
const timestamp = Date.now();
const tokenData = `${email}|${timestamp}|${secret}`;
const token = Buffer.from(tokenData).toString('base64');

return [{json: {
  ok: true,
  token,
  email,
  nombre: user.nombre,
  role: user.role
}}];

// Validar token para llamadas subsecuentes
// Llamar como: POST /crack-tesos/auth/validate con header Authorization: Bearer [token]
const authHeader = $input.first().json.headers['authorization'] || '';
const token = authHeader.replace('Bearer ', '').trim();

if (!token) return [{json: {ok: false, valid: false}}];

try {
  const decoded = Buffer.from(token, 'base64').toString('utf8');
  const parts = decoded.split('|');
  if (parts.length !== 3) return [{json: {ok: true, valid: false}}];

  const [email, timestamp, secret] = parts;
  if (secret !== 'CrackTesos2026_Admin_Token') return [{json: {ok: true, valid: false}}];

  // Token válido por 8 horas
  const tokenAge = Date.now() - parseInt(timestamp);
  if (tokenAge > 8 * 3600 * 1000) return [{json: {ok: true, valid: false, error: 'Sesión expirada'}}];

  return [{json: {ok: true, valid: true, email}}];
} catch(e) {
  return [{json: {ok: true, valid: false}}];
}
